        params = self.get_params(ctx)
        opt_to_name = {
            opt: param.name
            for param in params
            if isinstance(param, Option)
            for opt in (*param.opts, *param.secondary_opts)
        }

        for param in params:
            if not isinstance(param, Option) or param._dynamic_default is None:
                continue

